import{_ as e,o as r,c as i,ah as p}from"./chunks/framework.BNo2o5Ln.js";const b=JSON.parse('{"title":"限流降级","description":"","frontmatter":{"title":"限流降级","order":2},"headers":[],"relativePath":"server/distribute/qos/slashing/index.md","filePath":"server/distribute/qos/slashing/index.md"}'),n={name:"server/distribute/qos/slashing/index.md"};function l(h,a,t,s,d,o){return r(),i("div",null,[...a[0]||(a[0]=[p('<h1 id="限流降级" tabindex="-1">限流降级 <a class="header-anchor" href="#限流降级" aria-label="Permalink to “限流降级”">​</a></h1><p>限流降级是保护服务的重要手段，限流防止服务被过载请求打垮，降级保证核心功能可用。限流降级是系统自我保护的第一道防线。</p><h2 id="限流" tabindex="-1">限流 <a class="header-anchor" href="#限流" aria-label="Permalink to “限流”">​</a></h2><h3 id="为什么需要限流" tabindex="-1">为什么需要限流 <a class="header-anchor" href="#为什么需要限流" aria-label="Permalink to “为什么需要限流”">​</a></h3><p>保护服务：服务容量有限，超过容量的请求会导致服务响应变慢或崩溃。</p><p>保护依赖：服务依赖的第三方服务有容量限制，超过限制会被封禁。</p><p>防止雪崩：服务故障时，限流可以减少故障服务的请求，避免雪崩。</p><h3 id="限流算法" tabindex="-1">限流算法 <a class="header-anchor" href="#限流算法" aria-label="Permalink to “限流算法”">​</a></h3><p>固定窗口：将时间分成固定大小的窗口，每个窗口内限制请求数。简单但窗口边界问题。</p><p>滑动窗口：将时间分成更小的单元，记录每个单元的请求数。平滑无边界问题。</p><p>令牌桶：以恒定速率放入令牌，请求消耗令牌。可以应对突发流量。</p><p>漏桶：以恒定速率处理请求，平滑输出。</p><h3 id="限流维度" tabindex="-1">限流维度 <a class="header-anchor" href="#限流维度" aria-label="Permalink to “限流维度”">​</a></h3><p>QPS 限流：每秒请求数限流，适用于短时间请求。</p><p>并发限流：并发请求数限流，适用于长连接请求。</p><p>用户限流：根据用户 ID 限流，防止个别用户占用过多资源。</p><p>IP 限流：根据 IP 限流，防止恶意攻击。</p><h3 id="限流策略" tabindex="-1">限流策略 <a class="header-anchor" href="#限流策略" aria-label="Permalink to “限流策略”">​</a></h3><p>直接拒绝：请求超过限流阈值时直接拒绝，返回错误码或错误信息。</p><p>排队等待：请求超过限流阈值时排队等待，有请求完成则处理排队请求。</p><p>Warm Up：限流阈值从较小值逐渐增加到目标值，避免系统启动时大量请求导致故障。</p><p>匀速排队：请求以匀速通过，平滑处理请求。</p><h2 id="降级" tabindex="-1">降级 <a class="header-anchor" href="#降级" aria-label="Permalink to “降级”">​</a></h2><h3 id="为什么需要降级" tabindex="-1">为什么需要降级 <a class="header-anchor" href="#为什么需要降级" aria-label="Permalink to “为什么需要降级”">​</a></h3><p>服务故障时，保证核心功能可用，降低用户体验损失。</p><p>资源不足时，释放非核心功能的资源，确保核心功能正常运行。</p><h3 id="降级策略" tabindex="-1">降级策略 <a class="header-anchor" href="#降级策略" aria-label="Permalink to “降级策略”">​</a></h3><p>默认值：返回默认值，如空列表、空对象、固定值。</p><p>缓存：返回缓存的响应，如 Redis 缓存的响应。</p><p>本地兜底：执行本地逻辑，如查询本地数据库。</p><p>快速失败：直接返回错误，不执行任何逻辑。</p><p>关闭非核心功能：暂时关闭非核心功能，释放资源。</p><h3 id="降级级别" tabindex="-1">降级级别 <a class="header-anchor" href="#降级级别" aria-label="Permalink to “降级级别”">​</a></h3><p>一级降级：核心功能降级，如订单创建失败返回友好提示。</p><p>二级降级：重要功能降级，如推荐服务故障返回热门商品。</p><p>三级降级：非核心功能降级，如评论服务故障直接关闭评论功能。</p><h3 id="自动降级" tabindex="-1">自动降级 <a class="header-anchor" href="#自动降级" aria-label="Permalink to “自动降级”">​</a></h3><p>超时降级：请求超时自动降级，返回默认值。</p><p>异常降级：请求异常（如异常率超过阈值）自动降级。</p><p>限流降级：请求被限流自动降级，返回限流提示。</p><h2 id="限流降级的实现" tabindex="-1">限流降级的实现 <a class="header-anchor" href="#限流降级的实现" aria-label="Permalink to “限流降级的实现”">​</a></h2><h3 id="sentinel" tabindex="-1">Sentinel <a class="header-anchor" href="#sentinel" aria-label="Permalink to “Sentinel”">​</a></h3><p>Sentinel 是阿里开源的流量防卫组件，提供限流、熔断降级、系统保护。</p><p>Sentinel 的限流：QPS 限流、并发线程数限流、热点参数限流。</p><p>Sentinel 的降级：慢调用比例、异常比例、异常数。</p><p>Sentinel 的优势：性能高、实时监控、规则动态配置。</p><h3 id="hystrix" tabindex="-1">Hystrix <a class="header-anchor" href="#hystrix" aria-label="Permalink to “Hystrix”">​</a></h3><p>Hystrix 是 Netflix 开源的熔断降级库，已停止维护。</p><p>Hystrix 的特性：熔断器、线程池隔离、信号量隔离、请求缓存、请求合并。</p><h3 id="resilience4j" tabindex="-1">Resilience4j <a class="header-anchor" href="#resilience4j" aria-label="Permalink to “Resilience4j”">​</a></h3><p>Resilience4j 是受 Hystrix 启发的容错库，提供熔断器、限流、重试、舱壁隔离。</p><p>Resilience4j 的优势：轻量级、模块化、性能高、维护活跃。</p><h2 id="限流降级的最佳实践" tabindex="-1">限流降级的最佳实践 <a class="header-anchor" href="#限流降级的最佳实践" aria-label="Permalink to “限流降级的最佳实践”">​</a></h2><p>分层限流：网关层限流（粗粒度）、应用层限流（细粒度），形成多级防护。</p><p>限流阈值设置：根据压测结果设置限流阈值，留有余量。</p><p>降级逻辑要简单：降级逻辑不应依赖其他服务，避免降级失败。</p><p>降级逻辑要有默认值：降级时返回默认值，保证核心功能可用。</p><p>监控限流降级：监控限流降级触发情况，分析限流降级原因，调整策略。</p><p>定期演练：定期进行限流降级演练，验证降级逻辑的有效性。</p><p>限流降级是保护服务的重要手段，合理使用限流降级，可以提高系统的稳定性和可用性。</p>',60)])])}const x=e(n,[["render",l]]);export{b as __pageData,x as default};
